sql:
SELECT COUNT(*)
FROM racers
WHERE division = 'PRO' AND country = 'USA';

SELECT alias, country
FROM racers
WHERE division = 'AMATEUR';

SELECT i.incident_id, i.description, ls.ranking, ls.ranking_score
FROM incidents i
JOIN leaderboard_submissions ls ON i.submission_id = ls.submission_id;

SELECT submission_id, status_id, ranking_score, ranking, last_updated, points_awarded, comments
FROM leaderboard_submissions
WHERE leaderboard_id = 1;

SELECT division, COUNT(*) AS "Number of racers"
FROM racers
GROUP BY division;

SELECT AVG(avg_lap_time) 
FROM submissions 
WHERE submission_id NOT IN (
  SELECT submission_id 
  FROM incidents
);

SELECT alias
FROM racers
WHERE racer_id IN (SELECT racer_id FROM submissions);

external_knowledge:
- "Frontrunners" refers to the top 3 racers; 
- "Arenas" is a metaphor for 'events'; 
- "Standings" represent the racers' rankings in the leaderboard; 
- "Scores" are the points assigned based on their performance; 
- "Last time they refreshed their glory" refers to the timestamp when their leaderboard entries were last updated; 
- "Medals" symbolize the points awarded for their submissions; 
- "Whispers" are the comments or notes about their submissions.
